var f = this, id = f.get_id(), n1 = 0, n2 = 0, v = f._language == 'v';
var g = f.getItem('ctsx')._controlBehavior, l1 = g._getColumnOrder('stt_rec_dh');
var e1 = (v ? 'Thông tin mã khách của lệnh sản xuất phải giống với đơn hàng.' : 'Manufacturing Order should have same customer information as Sales Order.');
var e2 = (v ? 'Dữ liệu trong chi tiết không được lấy từ nhiều đơn hàng.' : 'Data in grid form should not be extracted from Sales Orders.');
var d1 = f.getItemValue('ngay_kh1'), d2 = f.getItemValue('ngay_kh2'), d3 = f.getItemValue('ngay_th1'), d4 = f.getItemValue('ngay_th2'), e = null;
if (d1 != null && d2 != null && d1 > d2) e = 'ngay_kh2';
  else {if (d3 != null && d4 != null && d3 > d4) e = 'ngay_th2';}
if (e) {
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), f.getItem(e).field.Label), String.format('$find(\'{0}\').getItem(\'{1}\').focus()', f.get_id(), e));
}

var t = f.getItemValue('ma_kh'), v = '';
for (var i = 1; i <= g._rowCount; i++) {
  var v1 = (g._getItemValue(i, l1) != '');
  if (v1) {
    var u = g._getItem(i, 1)._customerIdentity;
    if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
    if (t != u) {
      $func.hideWait(id);
      $message.show(e1, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
      f._checked = false;
      break;
    }
    if (!v && v1) v = g._getItemValue(i, l1);
    if (v && v1) {
      if (v != g._getItemValue(i, l1)) {
        g._errorMultiOrderObject = g._getItem(1, g._getColumnOrder('ma_vt'));
        $func.hideWait(id);
        $message.show(e2, String.format('$find(\'{0}\').focus(\'ctsx\');$find(\'{1}\')._errorMultiOrderObject.focus()', id, g.get_id()));
        f._checked = false;
        break;
      }
    }
  }
}
